Here's a quick fix at first glance.

(How) would you like to integrate this behaviour ?

```
def data(self, root):
        '''Convert etree.Element into a dictionary'''
        value = self.dict()
        children = [node for node in root if isinstance(node.tag, basestring)]
        for attr, attrval in root.attrib.items():
            attr = attr if self.attr_prefix is None else self.attr_prefix + attr
            value[attr] = self._fromstring(attrval)
        if root.text and self.text_content is not None:
            text = root.text.strip()
            if text:
                if self.simple_text and len(children) == len(root.attrib) == 0:
                    value = self._fromstring(text)
                else:
                    value[self.text_content] = self._fromstring(text)
        count = Counter(child.tag for child in children)
        for child in children:
            #if count[child.tag] == 1:
            #    value.update(self.data(child))
            #else:
            result = value.setdefault(child.tag, self.list())
            result += self.data(child).values()
        return self.dict([(root.tag, value)])
```

This PR is way too opinionated to be merged.

1. Raising when a class is passed instead of an instance is typically okay, I have no strong opinion against this one.
2. Doing `self.add_cog(self)` has been done before and is not something I want to disallow just because some people find it weird or strange. Consider the following (currently valid) program that your PR will reject:

```py
class X(commands.Bot):
    def __init__(self):
        super().__init__(command_prefix='?')
        self.add_cog(self)

    @commands.command()
    def do(self, ctx, *, test: str):
        await ctx.send(test)

x = X()

@x.event
async def on_message(message):
    if message.author.bot:
        return
    await x.process_commands(message)
```
3. This noisy logging warning is way too opinionated. Consider the following valid program that might be a little weird but now raises a warning:

```py
class Baton:
    def __init__(self):
        self.money = 2000

    def take(self, x):
        if x >= self.money:
            ret = self.money
            self.money = 0
            return ret
        else:
            self.money -= x
            return x

    def put(self, x):
        self.money += x

class Bank:
    def __init__(self, bot):
        self.bot = bot

    @commands.command()
    async withdraw(self, ctx, *, amount: int):
        baton = self.bot.get_cog('Baton')
        taken = baton.take(amount)
        await ctx.send(f'withdrew {taken}')

bot.add_cog(Baton())
bot.add_cog(Bank(bot))
```

Hi @getvivekv!

You can use the [`refreshWidget` method](http://mottie.github.io/tablesorter/docs/#refreshwidgets). Try [this demo](http://jsfiddle.net/e3V9V/196/).

```js
var $table = $("table").tablesorter({
    theme: "bootstrap",
    widthFixed: true,
    headerTemplate: "{content} {icon}",
    widgets: ["uitheme", "filter", "zebra"],
    widgetOptions: {
        filter_reset: ".reset"
    }
});

$('button').click(function(){
    $(this).toggleClass('nofilter');
    var widgets = ['uitheme', 'zebra'],
        noFilter = !$(this).hasClass('nofilter');
    if (noFilter) {
        widgets.push('filter');
    }
    $table[0].config.widgets = widgets;
    // refresh widgets
    $table.trigger('refreshWidgets');
    // hide filter reset button
    $('.reset').toggle(noFilter);
});
```

In that case, try binding to both:

```js
$('table').on('filterEnd pagerChange', function(){
  $( 'table' ).trigger( 'lazyloadUpdate' );
});
```

